/// TOLC + 7 Living Mercy Gates Evaluation Module
/// Used to assess proposals generated by the self-evolution loop.
/// 
/// Refined metrics + improved prompt + output validation layer.

use llama_cpp_gguf::{generate_chat, ChatMessage, GenerationConfig, LlamaModel};
use regex::Regex;

#[derive(Debug, Clone)]
pub struct EvaluationResult {
    pub truth_score: f32,
    pub order_score: f32,
    pub logic_score: f32,
    pub compassion_score: f32,

    pub truth_gate_score: f32,
    pub order_gate_score: f32,
    pub logic_gate_score: f32,
    pub compassion_gate_score: f32,
    pub non_harm_gate_score: f32,
    pub harmony_gate_score: f32,
    pub abundance_gate_score: f32,
    pub sovereignty_gate_score: f32,

    pub average_tolc_score: f32,
    pub average_mercy_score: f32,

    pub passes_threshold: bool,
    pub summary: String,
    pub detailed_feedback: String,
}

impl EvaluationResult {
    /// Returns true only if the proposal passes the LLM threshold
    /// AND meets minimum mercy standards on the most critical gates.
    pub fn is_acceptable(&self) -> bool {
        self.passes_threshold
            && self.sovereignty_gate_score >= 7.0
            && self.non_harm_gate_score >= 6.0
            && self.harmony_gate_score >= 6.0
    }
}

/// Lightweight validation of LLM output.
/// Ensures scores are within expected range.
fn validate_scores(json: &serde_json::Value) -> bool {
    let keys = [
        "truth_score", "order_score", "logic_score", "compassion_score",
        "truth_gate_score", "order_gate_score", "logic_gate_score", "compassion_gate_score",
        "non_harm_gate_score", "harmony_gate_score", "abundance_gate_score", "sovereignty_gate_score",
    ];

    for key in keys {
        if let Some(score) = json[key].as_f64() {
            if !(0.0..=10.0).contains(&score) {
                return false;
            }
        } else {
            return false;
        }
    }
    true
}

/// Evaluate a proposal using TOLC + the 7 Living Mercy Gates via LLM
/// with robust regex-based JSON extraction and output validation.
pub fn evaluate_proposal_with_tolc_and_mercy(
    model: &LlamaModel,
    proposal: &str,
) -> EvaluationResult {
    let prompt = format!(
        r#"You are a rigorous, impartial evaluator for Rathor.ai's self-evolution system.

Your task is to evaluate the following proposal using the TOLC framework and the 7 Living Mercy Gates.
Be honest, consistent, and realistic in your scoring. Avoid overly generous or harsh scoring unless clearly justified.

**Proposal to Evaluate:**
{}

**Evaluation Framework:**

**TOLC Principles (score 0-10 each):**
- Truth: Based on verifiable facts and honest assessment?
- Order: Increases healthy structure and reduces unnecessary complexity?
- Logic: Internally consistent with no contradictions?
- Compassion: Considers well-being and impact on affected beings?

**7 Living Mercy Gates (score 0-10 each):**
Truth Gate, Order Gate, Logic Gate, Compassion Gate, Non-Harm Gate, Harmony Gate, Abundance Gate, Sovereignty Gate.

**Important Guidance:**
- Sovereignty is especially important. Assess whether the proposal preserves meaningful autonomy and future optionality.
- Be conservative with high scores. Most proposals should land in the 4-8 range unless exceptionally strong.
- Non-Harm and Harmony should not be ignored even if other dimensions are strong.

**Output Instructions:**
Respond ONLY with valid JSON in this exact format. Do not include any text outside the JSON object.

{{
  "truth_score": <0-10>,
  "order_score": <0-10>,
  "logic_score": <0-10>,
  "compassion_score": <0-10>,
  "truth_gate_score": <0-10>,
  "order_gate_score": <0-10>,
  "logic_gate_score": <0-10>,
  "compassion_gate_score": <0-10>,
  "non_harm_gate_score": <0-10>,
  "harmony_gate_score": <0-10>,
  "abundance_gate_score": <0-10>,
  "sovereignty_gate_score": <0-10>,
  "passes_threshold": <true or false>,
  "summary": "One paragraph summary of the evaluation",
  "detailed_feedback": "Key observations, strengths, and concerns"
}}"#,
        proposal
    );

    let messages = vec![ChatMessage {
        role: "user".to_string(),
        content: prompt,
    }];

    let raw_response = generate_chat(model, &messages, &GenerationConfig::default())
        .unwrap_or_default();

    // Robust regex-based JSON extraction
    let json_str = extract_json_from_response(&raw_response);

    match serde_json::from_str::<serde_json::Value>(&json_str) {
        Ok(json) => {
            if !validate_scores(&json) {
                return EvaluationResult {
                    truth_score: 0.0,
                    order_score: 0.0,
                    logic_score: 0.0,
                    compassion_score: 0.0,
                    truth_gate_score: 0.0,
                    order_gate_score: 0.0,
                    logic_gate_score: 0.0,
                    compassion_gate_score: 0.0,
                    non_harm_gate_score: 0.0,
                    harmony_gate_score: 0.0,
                    abundance_gate_score: 0.0,
                    sovereignty_gate_score: 0.0,
                    average_tolc_score: 0.0,
                    average_mercy_score: 0.0,
                    passes_threshold: false,
                    summary: "Evaluation failed validation (invalid scores)".to_string(),
                    detailed_feedback: json_str,
                };
            }

            EvaluationResult {
                truth_score: json["truth_score"].as_f64().unwrap_or(0.0) as f32,
                order_score: json["order_score"].as_f64().unwrap_or(0.0) as f32,
                logic_score: json["logic_score"].as_f64().unwrap_or(0.0) as f32,
                compassion_score: json["compassion_score"].as_f64().unwrap_or(0.0) as f32,

                truth_gate_score: json["truth_gate_score"].as_f64().unwrap_or(0.0) as f32,
                order_gate_score: json["order_gate_score"].as_f64().unwrap_or(0.0) as f32,
                logic_gate_score: json["logic_gate_score"].as_f64().unwrap_or(0.0) as f32,
                compassion_gate_score: json["compassion_gate_score"].as_f64().unwrap_or(0.0) as f32,
                non_harm_gate_score: json["non_harm_gate_score"].as_f64().unwrap_or(0.0) as f32,
                harmony_gate_score: json["harmony_gate_score"].as_f64().unwrap_or(0.0) as f32,
                abundance_gate_score: json["abundance_gate_score"].as_f64().unwrap_or(0.0) as f32,
                sovereignty_gate_score: json["sovereignty_gate_score"].as_f64().unwrap_or(0.0) as f32,

                average_tolc_score: (
                    json["truth_score"].as_f64().unwrap_or(0.0) +
                    json["order_score"].as_f64().unwrap_or(0.0) +
                    json["logic_score"].as_f64().unwrap_or(0.0) +
                    json["compassion_score"].as_f64().unwrap_or(0.0)
                ) as f32 / 4.0,

                average_mercy_score: (
                    json["truth_gate_score"].as_f64().unwrap_or(0.0) +
                    json["order_gate_score"].as_f64().unwrap_or(0.0) +
                    json["logic_gate_score"].as_f64().unwrap_or(0.0) +
                    json["compassion_gate_score"].as_f64().unwrap_or(0.0) +
                    json["non_harm_gate_score"].as_f64().unwrap_or(0.0) +
                    json["harmony_gate_score"].as_f64().unwrap_or(0.0) +
                    json["abundance_gate_score"].as_f64().unwrap_or(0.0) +
                    json["sovereignty_gate_score"].as_f64().unwrap_or(0.0)
                ) as f32 / 8.0,

                passes_threshold: json["passes_threshold"].as_bool().unwrap_or(false),
                summary: json["summary"].as_str().unwrap_or("").to_string(),
                detailed_feedback: json["detailed_feedback"].as_str().unwrap_or("").to_string(),
            }
        }
        Err(_) => EvaluationResult {
            truth_score: 0.0,
            order_score: 0.0,
            logic_score: 0.0,
            compassion_score: 0.0,
            truth_gate_score: 0.0,
            order_gate_score: 0.0,
            logic_gate_score: 0.0,
            compassion_gate_score: 0.0,
            non_harm_gate_score: 0.0,
            harmony_gate_score: 0.0,
            abundance_gate_score: 0.0,
            sovereignty_gate_score: 0.0,
            average_tolc_score: 0.0,
            average_mercy_score: 0.0,
            passes_threshold: false,
            summary: "Failed to parse evaluation response".to_string(),
            detailed_feedback: raw_response,
        },
    }
}

/// Extracts JSON from LLM response using multiple strategies for maximum robustness.
/// Strategy 1: Clean JSON object
/// Strategy 2: Markdown code block (```json or ```)
/// Strategy 3: First JSON-like object in text
/// Strategy 4: Fallback to trimmed original (upper layers will surface clear failure)
fn extract_json_from_response(response: &str) -> String {
    let trimmed = response.trim();

    // Strategy 1: Already clean JSON
    if trimmed.starts_with('{') && trimmed.ends_with('}') {
        return trimmed.to_string();
    }

    // Strategy 2: Markdown code block (```json or ```)
    let re_code = Regex::new(r"```(?:json)?\s*([\s\S]*?)\s*```").unwrap();
    if let Some(caps) = re_code.captures(trimmed) {
        if let Some(m) = caps.get(1) {
            let candidate = m.as_str().trim();
            if candidate.starts_with('{') && candidate.ends_with('}') {
                return candidate.to_string();
            }
        }
    }

    // Strategy 3: First JSON-like object in the text
    let re_json = Regex::new(r"(\{[\s\S]*\})").unwrap();
    if let Some(caps) = re_json.captures(trimmed) {
        if let Some(m) = caps.get(1) {
            return m.as_str().to_string();
        }
    }

    // Strategy 4: Return original (will fail upper layer with clear message)
    trimmed.to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_extract_json_raw() {
        let input = r#"{"truth_score": 8.5, "order_score": 9.0}"#;
        let result = extract_json_from_response(input);
        assert!(result.contains("truth_score"));
        assert!(result.starts_with('{') && result.ends_with('}'));
    }

    #[test]
    fn test_extract_json_markdown() {
        let input = r#"Here is the evaluation:

```json
{"logic_score": 7.5, "compassion_score": 8.0}
```

End of response."#;
        let result = extract_json_from_response(input);
        assert!(result.contains("logic_score"));
        assert!(!result.contains("```"));
        assert!(result.starts_with('{'));
    }

    #[test]
    fn test_extract_json_noisy() {
        let input = r#"Some introductory text and explanation before the data.
{ "non_harm_gate_score": 9.5, "harmony_gate_score": 8.8, "extra": "ignored" }
and trailing commentary after."#;
        let result = extract_json_from_response(input);
        assert!(result.contains("non_harm_gate_score"));
        assert!(result.contains("harmony_gate_score"));
    }

    #[test]
    fn test_extract_json_fallback() {
        let input = r#"This response contains no valid JSON structure at all, just plain text explanation."#;
        let result = extract_json_from_response(input);
        assert_eq!(result, input.trim());
    }
}